+func isLineRangeSuffix(s string) bool {
+	if s == "" {
+		return false
+	}
+	hyphens := 0
+	digits := 0
+	for i := 0; i < len(s); i++ {
+		switch c := s[i]; {
+		case c >= '0' && c <= '9':
+			digits++
+		case c == '-':
+			hyphens++
+			if hyphens > 1 {
+				return false
+			}
+		default:
+			return false
+		}
+	}
+
+	// Must include at least one digit; a lone "-" is not a valid range.
+	if digits == 0 {
+		return false
+	}
+
+	// If a hyphen is present, at least one side must be non-empty.
+	if hyphens == 1 {
+		parts := strings.SplitN(s, "-", 2)
+		return !(parts[0] == "" && parts[1] == "")
+	}
+
+	return true
+}
